import{_ as t,o as r,c as i,a3 as o}from"./chunks/framework.DACwFHq9.js";const b=JSON.parse('{"title":"Website View","description":"How the Notely website preview works — live local server, note rendering, project index, and full-text search.","frontmatter":{"title":"Website View","description":"How the Notely website preview works — live local server, note rendering, project index, and full-text search.","keywords":"website view, web preview, local server, note rendering, search index, markdown","category":"User Guide"},"headers":[],"relativePath":"web-view.md","filePath":"web-view.md","lastUpdated":1784869909000}'),a={name:"web-view.md"};function d(s,e,n,l,c,h){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="website-view" tabindex="-1">Website View <a class="header-anchor" href="#website-view" aria-label="Permalink to &quot;Website View&quot;">​</a></h1><p>The <strong>Website View</strong> renders your workspace notes as a fully navigable, styled static website served locally by Notely. Unlike the in-editor Markdown Preview pane, the website view runs inside your browser and includes a project index, full-text search, and cross-note navigation.</p><hr><h2 id="opening-the-website-view" tabindex="-1">Opening the Website View <a class="header-anchor" href="#opening-the-website-view" aria-label="Permalink to &quot;Opening the Website View&quot;">​</a></h2><p>Access via the <strong>Web</strong> top-level menu:</p><table tabindex="0"><thead><tr><th>Action</th><th>Context</th><th>Shortcut</th></tr></thead><tbody><tr><td><strong>Web → Open Project Website</strong></td><td>Landing screen (no note open)</td><td><code>Ctrl/Cmd + Shift + W</code></td></tr><tr><td><strong>Web → Open Current Note Website View</strong></td><td>When a note is active</td><td><code>Ctrl/Cmd + Shift + W</code></td></tr></tbody></table><p>Both actions start the local preview server (if not already running) and open the rendered page in your default browser.</p><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><h3 id="local-http-server" tabindex="-1">Local HTTP Server <a class="header-anchor" href="#local-http-server" aria-label="Permalink to &quot;Local HTTP Server&quot;">​</a></h3><p>Notely starts a <strong>local HTTP server</strong> (<code>webPreview.cjs</code>) on a random available port. The server binds to <code>127.0.0.1</code> only and is never accessible from other devices.</p><p>The server handles five route types:</p><table tabindex="0"><thead><tr><th>Route</th><th>What it serves</th></tr></thead><tbody><tr><td><code>GET /</code></td><td>Project index page — a listing of all workspace notes</td></tr><tr><td><code>GET /view/{note-path}</code></td><td>Individual note rendered as a website page</td></tr><tr><td><code>GET /pdf/{note-path}</code></td><td>Note rendered in PDF-optimised layout</td></tr><tr><td><code>GET /search</code></td><td>Full-text search results page</td></tr><tr><td><code>GET /search-index.json</code></td><td>Search index JSON (used by the search page)</td></tr><tr><td><code>GET /raw/{asset-path}</code></td><td>Static file passthrough for media assets (images, PDFs, Excalidraw PNGs)</td></tr></tbody></table><p>All responses include <code>Cache-Control: no-store</code> so you always see the latest saved version.</p><h3 id="live-content-overrides" tabindex="-1">Live Content Overrides <a class="header-anchor" href="#live-content-overrides" aria-label="Permalink to &quot;Live Content Overrides&quot;">​</a></h3><p>When you open the current note&#39;s website view while editing, Notely passes the <strong>unsaved editor buffer</strong> as a content override so you see real-time changes without needing to save first.</p><hr><h2 id="page-rendering-pipeline-websiterenderer-cjs" tabindex="-1">Page Rendering Pipeline (<code>websiteRenderer.cjs</code>) <a class="header-anchor" href="#page-rendering-pipeline-websiterenderer-cjs" aria-label="Permalink to &quot;Page Rendering Pipeline (`websiteRenderer.cjs`)&quot;">​</a></h2><p>Each note is processed through a custom rendering pipeline before being served:</p><ol><li><strong>Markdown-It parser</strong> with <code>linkify</code> and <code>typographer</code> enabled.</li><li><strong>Syntax highlighting</strong> (<code>highlight.js</code>) with numbered lines and a one-click copy button on every code block.</li><li><strong>Heading slug generation</strong> — all headings get deterministic <code>id</code> attributes (deduplicated with counters) enabling anchor links.</li><li><strong>Asset path rewriting</strong> — relative image/media paths are rewritten to <code>/raw/{path}</code> server routes. Legacy Excalidraw diagram paths are automatically migrated to the current <code>.notes-app/excali-diagrams/</code> layout.</li><li><strong>Markdown link rewriting</strong> — <code>.md</code> links become <code>/view/{note-path}</code> server routes, enabling seamless cross-note navigation.</li><li><strong>HTML injection</strong> into <code>websiteTemplate.cjs</code> which adds navigation, project sidebar, and the Notely website stylesheet.</li></ol><h3 id="what-renders-in-website-view" tabindex="-1">What renders in website view <a class="header-anchor" href="#what-renders-in-website-view" aria-label="Permalink to &quot;What renders in website view&quot;">​</a></h3><ul><li>Standard GFM markdown (headings, lists, tables, blockquotes, task lists)</li><li>Fenced code blocks with syntax highlighting and line numbers</li><li>Inline and block images (<code>.png</code>, <code>.jpg</code>, <code>.gif</code>, <code>.svg</code>, <code>.webp</code>)</li><li>Embedded Excalidraw diagram previews (rendered PNG thumbnails)</li><li>Embedded PDF documents</li><li>Cross-note Wikilinks and relative <code>.md</code> links</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Mermaid diagram live rendering is handled client-side via a Mermaid.js script tag injected by <code>websiteTemplate.cjs</code>.</p></div><hr><h2 id="project-index-page" tabindex="-1">Project Index Page <a class="header-anchor" href="#project-index-page" aria-label="Permalink to &quot;Project Index Page&quot;">​</a></h2><p>The root <code>/</code> page lists all <code>.md</code> files in the active workspace (or project scope), sorted alphabetically. Notes in excluded directories (<code>.notes-app/</code>, <code>.git/</code>, <code>node_modules/</code>) are omitted.</p><hr><h2 id="full-text-search" tabindex="-1">Full-Text Search <a class="header-anchor" href="#full-text-search" aria-label="Permalink to &quot;Full-Text Search&quot;">​</a></h2><p>The <code>/search</code> page provides client-side full-text search across all workspace notes:</p><ul><li>The server builds a <strong>search index JSON</strong> (<code>/search-index.json</code>) by reading and indexing all <code>.md</code> files in scope at request time.</li><li>The search page fetches this JSON and runs matching in the browser — no external search service required.</li><li>Results include the note title, matching excerpt, and a direct link to the note&#39;s website view.</li></ul><hr><h2 id="website-scope" tabindex="-1">Website Scope <a class="header-anchor" href="#website-scope" aria-label="Permalink to &quot;Website Scope&quot;">​</a></h2><p>The website scope tracks the <strong>active project</strong> (or workspace root if no project is open):</p><ul><li>Switching workspace or project updates the scope — the server scope syncs on the next page load.</li><li>On scope change, the content override cache is cleared so you don&#39;t see stale overrides from a previous workspace.</li></ul><hr><h2 id="comparison-website-view-vs-preview-pane-vs-pdf-export" tabindex="-1">Comparison: Website View vs Preview Pane vs PDF Export <a class="header-anchor" href="#comparison-website-view-vs-preview-pane-vs-pdf-export" aria-label="Permalink to &quot;Comparison: Website View vs Preview Pane vs PDF Export&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Preview Pane</th><th>Website View</th><th>PDF Export</th></tr></thead><tbody><tr><td>Rendered in</td><td>Electron app window</td><td>Your browser</td><td>Headless Chromium</td></tr><tr><td>Navigation</td><td>Single note only</td><td>Cross-note links, project index</td><td>Single note only</td></tr><tr><td>Full-text search</td><td>❌</td><td>✅ (client-side)</td><td>❌</td></tr><tr><td>Live refresh</td><td>✅ (auto on typing)</td><td>Manual browser refresh</td><td>One-shot render</td></tr><tr><td>Media resolved</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Syntax highlighting</td><td>✅</td><td>✅ (with line numbers)</td><td>✅</td></tr><tr><td>Shareable output</td><td>❌</td><td>❌ (local only)</td><td>✅ (save as file)</td></tr></tbody></table><p>To publish the website view as a static site, use <strong>File → Export Workspace → Web Format</strong> which packages the full rendered HTML output as a <code>.zip</code> archive you can host on GitHub Pages, Netlify, or any static server. See <a href="/export-reference.html">Export Reference</a> for details.</p>',38)])])}const w=t(a,[["render",d]]);export{b as __pageData,w as default};
